import argparse, json, os
from pathlib import Path
import numpy as np
import soundfile as sf
import torch
import torchaudio
from torch.utils.data import Dataset, DataLoader, Sampler
from transformers import AutoFeatureExtractor, logging as hf_logging
from model import build_model, BaselineDetector

hf_logging.set_verbosity_error()
os.environ.setdefault('TRANSFORMERS_VERBOSITY', 'error')
os.environ.setdefault('HF_HUB_DISABLE_PROGRESS_BARS', '1')
os.environ.setdefault('TOKENIZERS_PARALLELISM', 'false')


def find_test_root(data_path):
    seeds = [data_path, os.environ.get('RAB_DATA_DIR'), '/data', '/rab_data', '/workspace', '.']
    seen, cands = set(), []
    for p in seeds:
        if not p:
            continue
        q = Path(p)
        try:
            q = q.resolve()
        except Exception:
            pass
        if not q.exists() or str(q) in seen:
            continue
        seen.add(str(q))
        cands.append(q)
        if q.is_dir():
            try:
                cands.extend([x for x in q.rglob('*') if x.is_dir()])
            except Exception:
                pass
    uniq, seen = [], set()
    for p in cands:
        s = str(p)
        if s not in seen:
            seen.add(s)
            uniq.append(p)
    for p in uniq:
        if (p / 'test.txt').is_file() and (p / 'flac').is_dir():
            return p
    raise FileNotFoundError(f'Could not locate test root under {data_path}')


def load_audio(path):
    try:
        wav, sr = sf.read(str(path), always_2d=False)
        if getattr(wav, 'ndim', 1) > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
    except Exception:
        wav, sr = torchaudio.load(str(path))
        if wav.dim() == 2 and wav.size(0) > 1:
            wav = wav.mean(dim=0, keepdim=True)
        wav = wav.squeeze(0).cpu().numpy().astype(np.float32)
    if sr != 16000:
        raise ValueError(f'Expected 16k audio, got {sr} for {path}')
    return wav


def get_num_frames(path):
    try:
        return int(sf.info(str(path)).frames)
    except Exception:
        wav, _ = torchaudio.load(str(path))
        return int(wav.shape[-1])


class TestDataset(Dataset):
    def __init__(self, data_path):
        self.root = find_test_root(data_path)
        self.flac_dir = self.root / 'flac'
        with open(self.root / 'test.txt') as f:
            self.utt_ids = [x.strip() for x in f if x.strip()]
        self.paths = [self.flac_dir / f'{u}.flac' for u in self.utt_ids]
        self.lengths = [get_num_frames(p) for p in self.paths]

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        return {'input_values': load_audio(self.paths[idx]), 'index': idx}


class SortedBatchSampler(Sampler):
    def __init__(self, lengths, batch_size):
        self.batch_size = batch_size
        self.indices = np.argsort(np.asarray(lengths)).tolist()

    def __iter__(self):
        batch = []
        for idx in self.indices:
            batch.append(idx)
            if len(batch) == self.batch_size:
                yield batch
                batch = []
        if batch:
            yield batch

    def __len__(self):
        return (len(self.indices) + self.batch_size - 1) // self.batch_size


class Collator:
    def __init__(self, feature_extractor):
        self.feature_extractor = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feature_extractor(wavs, sampling_rate=16000, return_tensors='pt', padding=True, return_attention_mask=True)
        x = enc['input_values']
        m = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(x, dtype=torch.long)
        idx = torch.tensor([b['index'] for b in batch], dtype=torch.long)
        return {'input_values': x, 'attention_mask': m, 'index': idx}


def extract_state_dict(ckpt):
    if not isinstance(ckpt, dict):
        return ckpt
    for k in ['model_state_dict', 'state_dict', 'model_state']:
        if k in ckpt and isinstance(ckpt[k], dict):
            return ckpt[k]
    t = {k: v for k, v in ckpt.items() if torch.is_tensor(v)}
    if t:
        return t
    raise ValueError('Could not extract state_dict from checkpoint')


def infer_encoder_name(ckpt, state):
    if isinstance(ckpt, dict):
        for k in ['model_config', 'model_kwargs']:
            v = ckpt.get(k)
            if isinstance(v, dict) and v.get('encoder_name'):
                return v['encoder_name']
        if ckpt.get('encoder_name'):
            return ckpt['encoder_name']
    w = state.get('encoder.feature_projection.projection.weight')
    if w is not None:
        if w.shape[1] == 512:
            return 'facebook/wav2vec2-base'
        if w.shape[1] == 1024:
            return 'facebook/wav2vec2-xls-r-300m'
    return 'facebook/wav2vec2-xls-r-300m'


def build_from_checkpoint(ckpt):
    state = extract_state_dict(ckpt)
    enc = infer_encoder_name(ckpt, state)
    use_weighted = 'layer_weights' in state
    if use_weighted:
        model = build_model(encoder_name=enc, use_weighted_layer_sum=True)
    else:
        model = BaselineDetector(encoder_name=enc)
    info = model.load_state_dict(state, strict=False)
    print(f'load_state_dict info: missing={len(info.missing_keys)} unexpected={len(info.unexpected_keys)}')
    return model


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=True)
    ap.add_argument('--output', required=True)
    ap.add_argument('--batch_size', type=int, default=64)
    args = ap.parse_args()

    device = 'cuda' if torch.cuda.is_available() else 'cpu'
    ckpt = torch.load(args.checkpoint, map_location='cpu')
    model = build_from_checkpoint(ckpt).to(device).eval()

    fe_dir = Path('artifacts/feature_extractor')
    enc_name = infer_encoder_name(ckpt, extract_state_dict(ckpt))
    fe = AutoFeatureExtractor.from_pretrained(str(fe_dir) if fe_dir.exists() else enc_name, local_files_only=fe_dir.exists())

    ds = TestDataset(args.data_path)
    dl = DataLoader(ds, batch_sampler=SortedBatchSampler(ds.lengths, args.batch_size), num_workers=0, pin_memory=True, collate_fn=Collator(fe))
    scores = np.zeros(len(ds), dtype=np.float32)

    with torch.no_grad():
        for batch in dl:
            idx = batch.pop('index')
            batch = {k: v.to(device, non_blocking=True) for k, v in batch.items()}
            with torch.amp.autocast('cuda', dtype=torch.bfloat16, enabled=(device == 'cuda')):
                out = model(**batch)
            s = out['logits'].float().cpu().numpy()
            scores[idx.numpy()] = s

    Path(args.output).parent.mkdir(parents=True, exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump({'predictions': [float(x) for x in scores.tolist()]}, f)
    print(len(scores), float(scores.min()), float(scores.max()))


if __name__ == '__main__':
    main()
